compliant:
struct Point {
    int x, y;

    Point(int x, int y) : x(x), y(y) {}  // Constructors are allowed
};

// Use free functions or move to a class
int getDistance(const Point& p) {
    return p.x + p.y;
}

void move(Point& p, int dx, int dy) {
    p.x += dx;
    p.y += dy;
}

// Or use a class instead
class PointClass {
public:
    int x, y;

    PointClass(int x, int y) : x(x), y(y) {}

    int getDistance() const {
        return x + y;
    }

    void move(int dx, int dy) {
        x += dx;
        y += dy;
    }
};
